class BankAccount:
    def __init__(self):
        self.__balance = 0

    def deposit(self, amount):
        if amount > 0:
            self.__balance += amount
        else:
            raise ValueError("Deposit amount must be positive")

    def withdraw(self, amount):
        if 0 < amount <= self.__balance:
            self.__balance -= amount
        elif amount <= 0:
            raise ValueError("Withdrawal amount must be positive")
        else:
            raise ValueError("Insufficient funds")

    def get_balance(self):
        return self.__balance

    def transfer(self, amount, destination):
        if not isinstance(destination, BankAccount):
            raise TypeError("Destination must be a BankAccount object")

        try:
            self.withdraw(amount)
        except ValueError as e:
            raise ValueError(f"Transfer failed: {e}")

        try:
            destination.deposit(amount)
        except ValueError as e:
            # recover the initial state of the source account if the deposit fails
            self.deposit(amount)
            raise ValueError(f"Transfer failed: {e}")
```

